221			return "", fmt.Errorf("triage hook: empty runner result")
222		}
223		text := strings.TrimSpace(result.CondensedOutput)
224		if text == "" {
225			text = strings.TrimSpace(result.Output)
226		}
227		if text == "" {
228			return "", fmt.Errorf("triage hook: empty output")
229		}
