299	type triageResultRaw struct {
300		Classification         string          `json:"classification,omitempty"`
301		RecommendedAction      string          `json:"recommended_action,omitempty"`
302		Rationale              string          `json:"rationale,omitempty"`
303		SuggestedAmendments    json.RawMessage `json:"suggested_amendments,omitempty"`
304		SuggestedFollowupBeads json.RawMessage `json:"suggested_followup_beads,omitempty"`
305	}
306	
307	func decodeTriageResult(payload string) TriageResult {
308		var raw triageResultRaw
309		if err := json.Unmarshal([]byte(payload), &raw); err != nil {
310			return malformedTriageResult("json", "invalid JSON object", payload)
311		}
312	
313		out := TriageResult{
314			Classification:    strings.TrimSpace(raw.Classification),
315			RecommendedAction: strings.TrimSpace(raw.RecommendedAction),
316			Rationale:         strings.TrimSpace(raw.Rationale),
317		}
318		out.SuggestedAmendments = []TriageAmendment{}
319		out.SuggestedFollowupBeads = []FollowupBead{}
320	
321		amendments, warnings := decodeTriageAmendments(raw.SuggestedAmendments)
322		out.SuggestedAmendments = amendments
323		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
324	
325		followups, warnings := decodeTriageFollowupBeads(raw.SuggestedFollowupBeads)
326		out.SuggestedFollowupBeads = followups
327		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
328	
329		out = normalizeTriageResult(out)
330		out = addTriageRequiredFieldWarnings(out)
331		return out
332	}
333	
334	func normalizeTriageResult(in TriageResult) TriageResult {
335		in.Classification = strings.TrimSpace(in.Classification)
336		in.RecommendedAction = strings.TrimSpace(in.RecommendedAction)
337		in.Rationale = strings.TrimSpace(in.Rationale)
338		if in.SuggestedAmendments == nil {
339			in.SuggestedAmendments = []TriageAmendment{}
340		}
341		if in.SuggestedFollowupBeads == nil {
342			in.SuggestedFollowupBeads = []FollowupBead{}
343		}
344		if in.Classification != "" && !isRecognizedTriageClassification(in.Classification) {
345			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "unknown classification", in.Classification))
346		}
347		if in.RecommendedAction != "" && !isRecognizedTriageRecommendedAction(in.RecommendedAction) {
348			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "unknown recommended_action", in.RecommendedAction))
349		}
350		if len(in.DecodeWarnings) > 0 {
351			in.Malformed = true
352		}
353		return in
354	}
355	
356	func addTriageRequiredFieldWarnings(in TriageResult) TriageResult {
357		if strings.TrimSpace(in.Classification) == "" {
358			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "missing classification", ""))
359		}
360		if strings.TrimSpace(in.RecommendedAction) == "" {
361			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "missing recommended_action", ""))
362		}
363		if len(in.DecodeWarnings) > 0 {
364			in.Malformed = true
365		}
366		return in
367	}
