369	func decodeTriageAmendments(raw json.RawMessage) ([]TriageAmendment, []TriageDecodeWarning) {
370		if isEmptyTriageRaw(raw) {
371			return []TriageAmendment{}, nil
372		}
373		if s, ok := decodeTriageString(raw); ok {
374			if isTriageEmptySentinel(s) {
375				return []TriageAmendment{}, nil
376			}
377			return []TriageAmendment{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_amendments", "expected array; got string; dropped field", s)}
378		}
379		var out []TriageAmendment
380		if err := json.Unmarshal(raw, &out); err != nil {
381			return []TriageAmendment{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_amendments", "expected array; dropped malformed field", string(raw))}
382		}
383		if out == nil {
384			out = []TriageAmendment{}
385		}
386		return out, nil
387	}
