181	func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
182		env := preClaimIntakePromptEnvelope{
183			Title:         strings.TrimSpace(b.Title),
184			Description:   strings.TrimSpace(b.Description),
185			Acceptance:    strings.TrimSpace(b.Acceptance),
186			Labels:        append([]string(nil), b.Labels...),
187			PriorAttempts: []preClaimIntakeAttempt{},
188			Depth:         beadDecompositionDepth(projectRoot, b),
189			Parent:        strings.TrimSpace(b.Parent),
190			Dependencies:  append([]string(nil), b.DepIDs()...),
191		}
192	
193		// Prior attempts are optional for the gate. If bead history is available,
194		// include the last few attempt/result summaries to help the classifier
195		// distinguish a first-pass atomic bead from repeated decomposition.
196		if store != nil {
197			if eventStore, ok := any(store).(interface {
198				Events(id string) ([]bead.BeadEvent, error)
199			}); ok {
200				if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
201					for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
202						ev := events[i]
203						if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
204							continue
205						}
206						env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
207							Status:    strings.TrimSpace(ev.Summary),
208							Rationale: strings.TrimSpace(ev.Body),
209						})
210					}
211				}
212			}
213		}
214	
215		body, err := json.MarshalIndent(env, "", "  ")
216		if err != nil {
217			return "", err
218		}
219	
220		var sb strings.Builder
221		sb.WriteString("MODE: intake\n")
222		sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
223		sb.WriteString("Use rewritten to improve prompt fitness: compress stale, duplicated, or noisy description prose, or expand a vague bead with durable context grounded in the repository or governing artifacts.\n")
224		sb.WriteString("Validated replacement is preferred over append-only amendment when it makes the bead a better implementation prompt.\n")
225		sb.WriteString("Preservation rules: non-scope items, governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, and dependency IDs (ddx-XXXXXXXX) must all appear in the replacement description.\n")
226		sb.WriteString("When preservation cannot be proven from durable anchors, or when rewriting would require inventing acceptance criteria, changing scope, or choosing between conflicting requirements, classify as operator_required.\n")
227		sb.WriteString("Return exactly one JSON object matching the intake schema with classification, confidence, reasoning, and optional rewrite fields.\n")
228		sb.WriteString("When classification is rewritten, include rewrite.changed_fields, rewrite.description, and rewrite.acceptance.\n")
229		sb.WriteString("Do not include prose or markdown.\n\n")
230		sb.WriteString("```json\n")
231		sb.Write(body)
232		sb.WriteString("\n```\n")
233		return sb.String(), nil
234	}
