332	func decodeCanonicalReadinessPayload(payload string) (PreClaimIntakeResult, error) {
333		var out preClaimReadinessPromptResult
334		if err := json.Unmarshal([]byte(payload), &out); err != nil {
335			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
336		}
337		detail := strings.TrimSpace(out.Reason)
338		if detail == "" {
339			detail = strings.TrimSpace(out.Detail)
340		}
341		rewrite := PreClaimIntakeRewrite{
342			Description:   strings.TrimSpace(out.Rewrite.Description),
343			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
344			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
345		}
346		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
347		case "actionable_atomic":
348			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
349		case "actionable_but_rewritten":
350			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
351		case "too_large_decomposed":
352			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail}, nil
353		case "operator_required", "human_review_required":
354			return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail}, nil
355		case "ambiguous_needs_human", "needs_human":
356			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
357		case "readiness_error", "system_unready":
358			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
359			classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, detail)
360			return PreClaimIntakeResult{
361				Outcome:      PreClaimIntakeError,
362				Reason:       classified.Reason,
363				SystemReason: classified.SystemReason,
364				Detail:       detail,
365			}, nil
366		case "":
367			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
368		default:
369			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
370		}
371	}
