373	func decodeReadinessClassificationPayload(payload string) (PreClaimIntakeResult, error) {
374		var out preClaimReadinessClassificationPromptResult
375		if err := json.Unmarshal([]byte(payload), &out); err != nil {
376			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
377		}
378		reasons := failedReadinessReasons(out.ReadinessChecks)
379		detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
380		classified := ClassifyReadiness(out.Classification, reasons, detail)
381		if detail == "" {
382			detail = readinessCheckEvidence(out.ReadinessChecks)
383		}
384		detail = readinessDetailWithReason(classified, detail)
385	
386		rewrite := PreClaimIntakeRewrite{
387			Description:   strings.TrimSpace(out.Rewrite.Description),
388			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
389			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
390		}
391		result := PreClaimIntakeResult{
392			Outcome:      classified.IntakeOutcome,
393			Reason:       classified.Reason,
394			SystemReason: classified.SystemReason,
395			Detail:       detail,
396		}
397		if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
398			result.Outcome = PreClaimIntakeActionableButRewritten
399			result.Rewrite = rewrite
400		}
401		return result, nil
402	}
