404	func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
405		reasons := make([]string, 0, len(checks))
406		for _, check := range checks {
407			verdict := strings.ToLower(strings.TrimSpace(check.Verdict))
408			if verdict != "fail" {
409				continue
410			}
411			if reason := strings.TrimSpace(check.Reason); reason != "" {
412				reasons = append(reasons, reason)
413			}
414		}
415		return reasons
416	}
