430	func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
431		detail = strings.TrimSpace(detail)
432		reason := strings.TrimSpace(classified.Reason)
433		if reason == "" {
434			return detail
435		}
436		if detail == "" {
437			return reason
438		}
439		if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
440			return detail
441		}
442		return reason + ": " + detail
443	}
