	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/easel/fizeau"
)

// DecomposeResult is the outcome of a runDecomposer invocation.
type DecomposeResult struct {
	Failed   bool
	Reason   string   // "timeout", "empty_output", "invalid_count", "malformed_child", "dispatch_error"
	ChildIDs []string
	CostUSD  float64
}

// decomposerChildSpec is one element of the decomposer agent's JSON array output.
type decomposerChildSpec struct {
	Title       string   `json:"title"`
	Description string   `json:"description"`
	Acceptance  string   `json:"acceptance"`
	Labels      []string `json:"labels"`
}

const decomposerPromptSource = "bead-lifecycle-decomposer"

// NewPostLadderExhaustionDecomposeHook constructs a PostLadderExhaustionHook
// that dispatches runDecomposer when the failure class is TooLarge. For any
// other class it returns Attempted=false so the caller falls through unchanged.
func NewPostLadderExhaustionDecomposeHook(
	projectRoot string,
	store ExecuteBeadLoopStore,
	rcfg config.ResolvedConfig,
	svc agentlib.FizeauService,
	runner AgentRunner,
	actor string,
) PostLadderExhaustionHook {
	return func(ctx context.Context, beadID string, class RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		if class != TooLarge {
			return &PostLadderExhaustionResult{Attempted: false}, nil
		}

		var history []bead.BeadEvent
		if events, err := store.Events(beadID); err == nil {
			history = events
		}

		res := runDecomposer(ctx, store, svc, runner, rcfg, projectRoot, beadID, actor, history)
		return &PostLadderExhaustionResult{
			Attempted: true,
			Succeeded: !res.Failed,
			Path:      Decompose,
			CostUSD:   res.CostUSD,
		}, nil
	}
}

// runDecomposer dispatches a smart+ tier agent to produce 2–5 child bead specs
// for beadID, then creates each child via store.Create with Parent=beadID,
// sets execution-eligible=false on the parent, and emits a decompose-applied event.
//
// Failure modes all return DecomposeResult{Failed: true, Reason: ...}:
//   - timeout: context cancelled or deadline exceeded during dispatch
//   - empty_output: agent returned no text
//   - invalid_count: parsed array has <1 or >5 children
//   - malformed_child: any child missing title, description, or acceptance
//   - dispatch_error: store or infrastructure error
func runDecomposer(
	ctx context.Context,
	store ExecuteBeadLoopStore,
	svc agentlib.FizeauService,
	runner AgentRunner,
	rcfg config.ResolvedConfig,
	projectRoot, beadID, actor string,
	failureHistory []bead.BeadEvent,
) DecomposeResult {
	b, err := store.Get(beadID)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "dispatch_error"}
	}

	prompt := buildDecomposerPrompt(b, failureHistory)

	result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
		Prompt:           prompt,
		WorkDir:          projectRoot,
		PromptSource:     decomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(ctx, projectRoot, svc, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	})
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) || errors.Is(err, context.Canceled) {
			return DecomposeResult{Failed: true, Reason: "timeout"}
		}
		return DecomposeResult{Failed: true, Reason: "dispatch_error"}
	}

	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		return DecomposeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
	}

	children, failReason := parseDecomposerOutput(text)
	if failReason != "" {
		return DecomposeResult{Failed: true, Reason: failReason, CostUSD: result.CostUSD}
	}

	at := time.Now().UTC()
	childIDs := make([]string, 0, len(children))
	for _, child := range children {
		nb := &bead.Bead{
			Title:       child.Title,
			Description: child.Description,
			Acceptance:  child.Acceptance,
			Labels:      append([]string(nil), child.Labels...),
			Parent:      beadID,
		}
		if err := store.Create(nb); err != nil {
			return DecomposeResult{Failed: true, Reason: "dispatch_error", CostUSD: result.CostUSD}
		}
		childIDs = append(childIDs, nb.ID)
	}

	_ = store.Update(beadID, func(b *bead.Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		b.Extra[bead.ExtraExecutionElig] = false
	})

	body, _ := json.Marshal(map[string]any{
		"child_ids": childIDs,
		"cost_usd":  result.CostUSD,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "decompose-applied",
		Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
		Body:      string(body),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: at,
	})

	return DecomposeResult{
		Failed:   false,
		ChildIDs: childIDs,
		CostUSD:  result.CostUSD,
	}
}

// parseDecomposerOutput extracts and validates a JSON array of child specs from
// the agent's raw text output. Returns (children, "") on success or (nil, reason)
// on failure.
func parseDecomposerOutput(text string) ([]decomposerChildSpec, string) {
	arrayStr, ok := extractJSONArrayCandidate(text)
	if !ok {
		// Fallback: try a JSON object with a "children" array key.
		if candidate, ok2 := extractJSONCandidate(text); ok2 {
			var obj struct {
				Children []decomposerChildSpec `json:"children"`
			}
			if jsonErr := json.Unmarshal([]byte(candidate), &obj); jsonErr == nil && len(obj.Children) > 0 {
				return validateDecomposerChildren(obj.Children)
			}
		}
		return nil, "empty_output"
	}

	var children []decomposerChildSpec
	if jsonErr := json.Unmarshal([]byte(arrayStr), &children); jsonErr != nil {
		return nil, "empty_output"
	}
	return validateDecomposerChildren(children)
}

// extractJSONArrayCandidate extracts the first JSON array ("[...]") from s,
// checking fenced code blocks first and then falling back to raw bracket scanning.
func extractJSONArrayCandidate(s string) (string, bool) {
	if c, ok := lastFencedBlock(s, "json"); ok {
		trimmed := strings.TrimSpace(c)
		if strings.HasPrefix(trimmed, "[") {
			return trimmed, true
		}
	}
	if c, ok := lastFencedBlock(s, ""); ok {
		trimmed := strings.TrimSpace(c)
		if strings.HasPrefix(trimmed, "[") {
			return trimmed, true
		}
	}
	start := strings.Index(s, "[")
	if start < 0 {
		return "", false
	}
	depth := 0
	for i := start; i < len(s); i++ {
		switch s[i] {
		case '[':
			depth++
		case ']':
			depth--
			if depth == 0 {
				return s[start : i+1], true
			}
		}
	}
	return "", false
}

// validateDecomposerChildren enforces the 1–5 count bound and requires each
// child to have non-empty title, description, and acceptance fields.
func validateDecomposerChildren(children []decomposerChildSpec) ([]decomposerChildSpec, string) {
	if len(children) < 1 || len(children) > 5 {
		return nil, "invalid_count"
	}
	for _, child := range children {
		if strings.TrimSpace(child.Title) == "" ||
			strings.TrimSpace(child.Description) == "" ||
			strings.TrimSpace(child.Acceptance) == "" {
			return nil, "malformed_child"
		}
	}
	return children, ""
}

type decomposerPromptBead struct {
	ID          string   `json:"id"`
	Title       string   `json:"title"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Labels      []string `json:"labels,omitempty"`
}

type decomposerHistoryEntry struct {
	Kind    string `json:"kind"`
	Summary string `json:"summary,omitempty"`
}

type decomposerPromptEnvelope struct {
	Bead           decomposerPromptBead     `json:"bead"`
	FailureHistory []decomposerHistoryEntry `json:"failure_history,omitempty"`
}

func buildDecomposerPrompt(b *bead.Bead, events []bead.BeadEvent) string {
	env := decomposerPromptEnvelope{
		Bead: decomposerPromptBead{
			ID:          b.ID,
			Title:       strings.TrimSpace(b.Title),
			Description: strings.TrimSpace(b.Description),
			Acceptance:  strings.TrimSpace(b.Acceptance),
			Labels:      append([]string(nil), b.Labels...),
		},
	}
	for _, ev := range events {
		switch ev.Kind {
		case "bead.result", "execute-bead", "per-bead-budget-exhausted":
			env.FailureHistory = append(env.FailureHistory, decomposerHistoryEntry{
				Kind:    ev.Kind,
				Summary: strings.TrimSpace(ev.Summary),
			})
		}
	}

	body, _ := json.MarshalIndent(env, "", "  ")

	var sb strings.Builder
	sb.WriteString("MODE: decompose\n")
	sb.WriteString("You are the bead decomposer. The bead below has been flagged as too large for a single execution attempt.\n")
	sb.WriteString("Decompose it into 2-5 independently executable child beads.\n")
	sb.WriteString("Return exactly one JSON array of child spec objects.\n")
	sb.WriteString("Each object must have: title (string), description (string), acceptance (string), labels ([]string).\n")
	sb.WriteString("Each child must have 3-6 numbered acceptance criteria and be independently executable.\n")
	sb.WriteString("Output ONLY the JSON array — no prose, no markdown.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String()
}

