307	func decodeTriageResult(payload string) TriageResult {
308		var raw triageResultRaw
309		if err := json.Unmarshal([]byte(payload), &raw); err != nil {
310			return malformedTriageResult("json", "invalid JSON object", payload)
311		}
312	
313		out := TriageResult{
314			Classification:    strings.TrimSpace(raw.Classification),
315			RecommendedAction: strings.TrimSpace(raw.RecommendedAction),
316			Rationale:         strings.TrimSpace(raw.Rationale),
317		}
318		out.SuggestedAmendments = []TriageAmendment{}
319		out.SuggestedFollowupBeads = []FollowupBead{}
320	
321		amendments, warnings := decodeTriageAmendments(raw.SuggestedAmendments)
322		out.SuggestedAmendments = amendments
323		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
324	
325		followups, warnings := decodeTriageFollowupBeads(raw.SuggestedFollowupBeads)
326		out.SuggestedFollowupBeads = followups
327		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
328	
329		out = normalizeTriageResult(out)
330		out = addTriageRequiredFieldWarnings(out)
331		return out
332	}
