435	func triageWarningExcerpt(raw string) string {
436		raw = strings.TrimSpace(raw)
437		if raw == "" {
438			return ""
439		}
440		raw = strings.Join(strings.Fields(raw), " ")
441		if len(raw) <= maxTriageWarningExcerptBytes {
442			return raw
443		}
444		const marker = "...[truncated]"
445		limit := maxTriageWarningExcerptBytes - len(marker)
446		if limit <= 0 {
447			return raw[:maxTriageWarningExcerptBytes]
448		}
449		return raw[:limit] + marker
450	}
