package agent

import (
	"context"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// funcAgentRunner adapts a function to the AgentRunner interface for decompose tests.
type funcAgentRunner struct {
	fn func(RunArgs) (*Result, error)
}

func (r *funcAgentRunner) Run(opts RunArgs) (*Result, error) {
	return r.fn(opts)
}

// TestPostLadderExhaustion_TriggersDecompose_ReviewTooLarge verifies that a
// TooLarge failure class routes to the decomposer hook and, on valid children,
// creates child beads and sets parent execution-eligible=false.
func TestPostLadderExhaustion_TriggersDecompose_ReviewTooLarge(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:          "ddx-decompose-hook-trigger",
		Title:       "decompose hook trigger test",
		Description: "parent bead description",
		Acceptance:  "1. test passes",
	}
	require.NoError(t, store.Create(b))

	// Pre-seed counter to 1 so the next budget exhaustion hits the threshold.
	require.NoError(t, incrementConsecutiveLadderExhaustions(store, b.ID))

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	const childJSON = `[` +
		`{"title":"Child A","description":"desc for A","acceptance":"1. AC1\n2. AC2","labels":["phase:1"]},` +
		`{"title":"Child B","description":"desc for B","acceptance":"1. AC1\n2. AC2","labels":["phase:2"]}` +
		`]`
	decomposerRunner := &funcAgentRunner{fn: func(_ RunArgs) (*Result, error) {
		return &Result{Output: childJSON}, nil
	}}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewPostLadderExhaustionDecomposeHook(
		t.TempDir(),
		store,
		rcfg,
		nil,
		decomposerRunner,
		"test-actor",
	)

	var hookResult *PostLadderExhaustionResult
	wrappedHook := PostLadderExhaustionHook(func(ctx context.Context, beadID string, class RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		res, err := hook(ctx, beadID, class)
		hookResult = res
		cancel()
		return res, err
	})

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ReviewTerminalClassTooLarge,
				Detail:    escalation.PerBeadBudgetExhaustedReason + ": $1.00 billed >= $0.50 per-bead budget",
				SessionID: "sess-decompose-hook",
			}, nil
		}),
	}

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: wrappedHook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-decompose-hook",
		WorkerID:                 "worker-decompose-hook",
	})

	require.NotNil(t, hookResult, "hook must have fired")
	assert.True(t, hookResult.Attempted, "hook must report Attempted=true for TooLarge class")
	assert.True(t, hookResult.Succeeded, "decomposer must succeed with valid children")
	assert.Equal(t, Decompose, hookResult.Path)

	// Parent must be marked execution-ineligible.
	parent, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, false, parent.Extra[bead.ExtraExecutionElig], "parent must be marked execution-ineligible after decomposition")

	// decompose-applied event must be emitted.
	events, err := store.Events(b.ID)
	require.NoError(t, err)
	var decomposed bool
	for _, ev := range events {
		if ev.Kind == "decompose-applied" {
			decomposed = true
			break
		}
	}
	assert.True(t, decomposed, "decompose-applied event must be emitted on parent bead")

	// Two child beads must have been created with Parent=b.ID.
	children, err := store.ReadAllFiltered(func(child bead.Bead) bool {
		return child.Parent == b.ID
	})
	require.NoError(t, err)
	assert.Len(t, children, 2, "two child beads must be created")
}

// TestDecomposerInvalidChildren_CountsAsFailure verifies that a decomposer
// response with more than 5 children returns Failed=true with reason="invalid_count".
func TestDecomposerInvalidChildren_CountsAsFailure(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:          "ddx-decompose-invalid-count",
		Title:       "invalid count test",
		Description: "desc",
		Acceptance:  "1. AC",
	}
	require.NoError(t, store.Create(b))

	// 6 children: more than the allowed maximum of 5.
	const sixChildrenJSON = `[` +
