		`]`
	runner := &funcAgentRunner{fn: func(_ RunArgs) (*Result, error) {
		return &Result{Output: sixChildrenJSON}, nil
	}}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	res := runDecomposer(context.Background(), store, nil, runner, rcfg, t.TempDir(), b.ID, "test-actor", nil)

